$ok = 0; $fail = 0
foreach ($img in $images) {
    $outPath = Join-Path $dest "day-$($img.day).jpg"
    try {
        Invoke-WebRequest -Uri $img.url -OutFile $outPath -UseBasicParsing -TimeoutSec 30
        $size = (Get-Item $outPath).Length
        Write-Host "Day $($img.day): $size bytes OK"
        $ok++
    } catch {
        Write-Host "Day $($img.day): FAILED - $_"
        $fail++
    }
}

Write-Host ""
Write-Host "Done: $ok ok, $fail failed"

# Now git commit and push
if ($ok -gt 0) {
    Set-Location "C:\Users\Rory\Documents\GitHub\isitgonedown"
    git add social-images/instagram/
    git commit -m "Add 29 Instagram social images for permanent hosting"
    git push origin main
    Write-Host ""
    Write-Host "Pushed to GitHub. Netlify will deploy automatically."
    Write-Host "Images will be available at: https://isitgonedown.com/social-images/instagram/day-N.jpg"
}

# Save result to log
"$(Get-Date) - Downloaded: $ok, Failed: $fail" | Out-File -FilePath "C:\Users\Rory\Documents\GitHub\isitgonedown\social-images\download-log.txt"
